from __future__ import annotations


def _row(symbol, market_cap, revenue_ttm, revenue_growth_yoy, gross_margin_ttm, operating_margin_ttm, net_margin_ttm, eps_ttm, eps_growth_yoy, free_cash_flow_ttm, free_cash_flow_margin, debt_to_equity, current_ratio, return_on_equity, pe_ratio, forward_pe, price_to_sales, price_to_free_cash_flow, analyst_rating=None):
    row = {
        "symbol": symbol,
        "market_cap": market_cap,
        "revenue_ttm": revenue_ttm,
        "revenue_growth_yoy": revenue_growth_yoy,
        "gross_margin_ttm": gross_margin_ttm,
        "operating_margin_ttm": operating_margin_ttm,
        "net_margin_ttm": net_margin_ttm,
        "eps_ttm": eps_ttm,
        "eps_growth_yoy": eps_growth_yoy,
        "free_cash_flow_ttm": free_cash_flow_ttm,
        "free_cash_flow_margin": free_cash_flow_margin,
        "debt_to_equity": debt_to_equity,
        "current_ratio": current_ratio,
        "return_on_equity": return_on_equity,
        "pe_ratio": pe_ratio,
        "forward_pe": forward_pe,
        "price_to_sales": price_to_sales,
        "price_to_free_cash_flow": price_to_free_cash_flow,
    }
    if analyst_rating is not None:
        row["analyst_rating"] = analyst_rating
    return row


